#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10,INF=(1<<31)-1;

struct Edge{
    int u,v,w;
}edge[N*5];

struct Node{
    int lc,rc,sum;
}tr[N*31];

int n,m,q,h[N],ls[N],root[N],tot,dfn[N*2],w[N],num,sz[N*2],val[N*2];
int f[N*2],b[N*2][21];
map<int,int> mp;
vector<int> e[N*2];

bool cmp(Edge x,Edge y){
    return x.w<y.w;
}

int father(int x){
    return f[x]==x?x:f[x]=father(f[x]);
}

void dfs(int x){
    for(int i=1;i<21;i++)
        b[x][i]=b[b[x][i-1]][i-1];
    dfn[x]=INF;
    if(x<=n){
        dfn[x]=++num;
        sz[x]=1;
        w[num]=x;
    }
    for(int y:e[x]){
        dfs(y);
        sz[x]+=sz[y];
        dfn[x]=min(dfn[x],dfn[y]);
    }
}

void modify(int p,int q,int l,int r,int x,int k){
    if(l==r){
        tr[p].sum=tr[q].sum+k;
        return;
    }
    int mid=l+r>>1;
    tr[p].lc=tr[q].lc;
    tr[p].rc=tr[q].rc;
    if(x<=mid){
        tr[p].lc=++tot;
        modify(tr[p].lc,tr[q].lc,l,mid,x,k);
    }else{
        tr[p].rc=++tot;
        modify(tr[p].rc,tr[q].rc,mid+1,r,x,k);
    }
    tr[p].sum=tr[tr[p].lc].sum+tr[tr[p].rc].sum;
}

int fnd(int x,int w){
    for(int i=20;i>=0;i--)
        if(val[b[x][i]]<=w && b[x][i])
            x=b[x][i];
    return x;
}

int query(int p,int q,int l,int r,int k){
    if(l==r)
        return l;
    int mid=l+r>>1;
    if(tr[tr[p].rc].sum-tr[tr[q].rc].sum>=k)
        return query(tr[p].rc,tr[q].rc,mid+1,r,k);
    else
        return query(tr[p].lc,tr[q].lc,l,mid,k-(tr[tr[p].rc].sum-tr[tr[q].rc].sum));
}

int main(){
    scanf("%d%d%d",&n,&m,&q);
    for(int i=1;i<=n;i++){
        scanf("%d",&h[i]);
        ls[i]=h[i];
    }
    for(int i=1;i<=m;i++)
        scanf("%d%d%d",&edge[i].u,&edge[i].v,&edge[i].w);
    sort(ls+1,ls+n+1);
    int len=unique(ls+1,ls+n+1)-ls-1;
    for(int i=1;i<=len;i++)
    	mp[ls[i]]=i;
    sort(edge+1,edge+m+1,cmp);
    for(int i=1;i<2*n;i++)
        f[i]=i;
    int now=n;
    for(int i=1;i<=m;i++){
        int fu=father(edge[i].u),fv=father(edge[i].v);
        if(fu!=fv){
            now++;
            e[now].push_back(fu);
            e[now].push_back(fv);
            f[fu]=f[fv]=now;
            b[fu][0]=b[fv][0]=now;
            val[now]=edge[i].w;
        }
    }
    val[0]=INF;
    for(int i=1;i<=now;i++)
        if(f[i]==i)
            dfs(i);
    for(int i=1;i<=n;i++){
        root[i]=++tot;
        modify(root[i],root[i-1],1,len,mp[h[w[i]]],1);
    }
    ls[0]=-1;
    int ans=0;
    while(q--){
        int v,x,k;
        scanf("%d%d%d",&v,&x,&k);
        v=(v^ans)%n+1;
        x^=ans;
        k=(k^ans)%n+1;
        int p=fnd(v,x);
        if(sz[p]<k)
            ans=-1;
        else
            ans=ls[query(root[dfn[p]+sz[p]-1],root[dfn[p]-1],1,len,k)];
        printf("%d\n",ans);
        ans=max(ans,0);
        //break;
    }
    return 0;
}
